"""Валидация конфигурации проекта: extract; image_processing по сценарию image_processing_logic."""from __future__ import annotationsimport jsonfrom dataclasses import dataclass, fieldfrom pathlib import Pathfrom typing import Anyfrom src.modules.file_extract import get_extract_settings_schemafrom src.modules.settings_schema.exceptions import SettingsSchemaErrorfrom .sections.image_processing_config import IMAGE_PROCESSING_KEYS, IMAGE_PROCESSING_LOGICS, ImageProcessingConfigfrom .sections.markdown_config import MarkdownConfigfrom .sections.pipeline_config import PipelineConfigfrom .sections.tagging_config import TaggingConfig# Допустимые коды провайдеров OCR/vision (image_processing)_VALID_OCR_PROVIDERS = ("mock", "yandex_ocr")_PROVIDER_API_ATTRS: dict[str, list[str]] = {}def _get_available_ocr_providers() -> list[str]:    state = ImageProcessingConfig.get_available_values()    return list(state.ocr_providers)def _get_available_vision_providers() -> list[str]:    state = ImageProcessingConfig.get_available_values()    return list(state.vision_providers)def _get_vision_models(provider: str) -> list[str]:    """Допустимые vision-модели для провайдера."""    state = ImageProcessingConfig.get_available_values()    return state.vision_models.get(provider, [])def _get_models_from_state(provider: str, group: str) -> list[str] | None:    """Список моделей из state для провайдера; None если не из state."""    state = ImageProcessingConfig.get_available_values()    if group == "multimodal" and provider in state.ocr_providers:        return state.ocr_models    return Nonedef _get_models(_provider: str, group: str) -> list[str]:    """Список допустимых моделей для валидации: из state или заглушка."""    from_state = _get_models_from_state(_provider, group)    if from_state is not None:        return from_state    if _provider == "yandex_ocr" and group == "multimodal":        from src.modules.yandex_ocr import MODEL_TYPES        return list(MODEL_TYPES)    return ["default"] if group in ("multimodal", "text") else []def _get_default_model_for_provider(provider: str, group: str) -> str | None:    if provider == "yandex_ocr" and group == "multimodal":        from src.modules.yandex_ocr import DEFAULT_MODEL        return DEFAULT_MODEL    return "default" if provider == "mock" else Nonedef _has_token(provider: str) -> bool:    return Truedef _image_processing_from_config_data(config_data: dict[str, Any]) -> tuple[str, dict[str, Any]]:    """Возвращает (image_processing_logic, image_processing dict)."""    ip = config_data.get("image_processing")    if not isinstance(ip, dict):        return IMAGE_PROCESSING_LOGICS.skip, {}    logic = (ip.get("image_processing_logic") or IMAGE_PROCESSING_LOGICS.skip).strip().lower()    return logic, ip@dataclassclass ValidationResult:    is_valid: bool    errors: list[str] = field(default_factory=list)    warnings: list[str] = field(default_factory=list)def validate_project_config(    project_root: Path,    config_data: dict[str, Any] | None = None,    *,    check_tokens: bool = True,) -> ValidationResult:    errors: list[str] = []    warnings: list[str] = []    if config_data is None:        config_path = project_root / "config.json"        if not config_path.exists():            errors.append(f"Конфиг не найден: {config_path}")            return ValidationResult(is_valid=False, errors=errors, warnings=warnings)        try:            raw = config_path.read_text(encoding="utf-8").strip()            config_data = json.loads(raw) if raw else {}        except json.JSONDecodeError as e:            errors.append(f"config.json — невалидный JSON: {e}")            return ValidationResult(is_valid=False, errors=errors, warnings=warnings)        if not isinstance(config_data, dict):            config_data = {}    logic, fp = _image_processing_from_config_data(config_data)    available_ocr = set(_get_available_ocr_providers())    available_vision = set(_get_available_vision_providers())    def _err_ocr(provider: str, model: str, prefix: str = "Обработка изображений: ") -> None:        if not provider:            errors.append(f"{prefix}ocr_provider не указан")            return        if provider not in _VALID_OCR_PROVIDERS:            errors.append(f"{prefix}Недопустимый ocr_provider: {provider}. Допустимы: {', '.join(_VALID_OCR_PROVIDERS)}")            return        if provider not in available_ocr:            errors.append(f"{prefix}Провайдер {provider} недоступен. Заполните секцию [API] в app.ini.")            return        allowed = _get_models(provider, "multimodal")        if not allowed:            errors.append(f"{prefix}У провайдера {provider} нет доступных моделей для OCR.")            return        default_m = _get_default_model_for_provider(provider, "multimodal")        effective = default_m if (model or "default").lower() == "default" else model        if effective not in allowed:            errors.append(f"{prefix}ocr_model '{model}' не в списке для {provider}. Допустимы: {', '.join(allowed)} или default")    def _err_vision(provider: str, model: str) -> None:        if not (provider or "").strip():            errors.append("Обработка изображений: vision_provider не указан")            return        if provider not in available_vision:            errors.append(f"Обработка изображений: Провайдер {provider} недоступен для Vision. Заполните секцию [API] в app.ini.")            return        allowed = _get_vision_models(provider)        if not allowed:            errors.append(f"Обработка изображений: У провайдера {provider} нет доступных vision-моделей.")            return        if (model or "").strip() not in allowed:            errors.append(f"Обработка изображений: vision_model '{model}' не в списке для {provider}. Допустимы: {', '.join(allowed)}")    if logic == IMAGE_PROCESSING_LOGICS.ocr_only:        _err_ocr(            (fp.get(IMAGE_PROCESSING_KEYS.ocr_provider) or "").strip().lower(),            (fp.get(IMAGE_PROCESSING_KEYS.ocr_model) or "").strip(),        )    elif logic == IMAGE_PROCESSING_LOGICS.vision_only:        _err_vision(            (fp.get(IMAGE_PROCESSING_KEYS.vision_provider) or "").strip(),            (fp.get(IMAGE_PROCESSING_KEYS.vision_model) or "").strip(),        )    # skip: модели не требуются    extract_raw = config_data.get("extract")    if extract_raw is not None and not isinstance(extract_raw, dict):        errors.append("Extract должен быть объектом.")    else:        extract_to_validate = extract_raw if isinstance(extract_raw, dict) else {}        try:            collection = get_extract_settings_schema()            collection.validate_values(extract_to_validate)        except SettingsSchemaError as e:            errors.append(f"Extract: {e!s}")    if check_tokens and logic != IMAGE_PROCESSING_LOGICS.skip:        if logic == IMAGE_PROCESSING_LOGICS.ocr_only:            ocr_p = (fp.get(IMAGE_PROCESSING_KEYS.ocr_provider) or "").strip().lower()            if ocr_p and ocr_p != "mock" and not _has_token(ocr_p):                keys = [a.upper() for a in _PROVIDER_API_ATTRS.get(ocr_p, [])]                errors.append(f"Для OCR провайдера {ocr_p} заполните в app.ini секцию [API], ключи: {', '.join(keys)}")    markdown_raw = config_data.get("markdown")    if markdown_raw is not None:        errors.extend(MarkdownConfig.validate(markdown_raw))    tagging_raw = config_data.get("tagging")    if tagging_raw is not None:        errors.extend(TaggingConfig.validate(tagging_raw))    pipeline_raw = config_data.get("pipeline")    if pipeline_raw is not None:        errors.extend(PipelineConfig.validate(pipeline_raw))    return ValidationResult(is_valid=len(errors) == 0, errors=errors, warnings=warnings)